**修复建议**:

```typescript
// 创建 src/utils/secrets.ts
export class SecretManager {
  private static secrets: Map<string, string> = new Map();

  static setSecret(key: string, value: string): void {
    this.secrets.set(key, value);
    // 从 process.env 中删除明文
    delete process.env[key];
  }

  static getSecret(key: string): string | undefined {
    return this.secrets.get(key);
  }

  static maskSecret(value: string): string {
    if (!value || value.length < 8) return '***';
    return `${value.slice(0, 4)}...${value.slice(-4)}`;
  }
}

// 使用示例
const apiKey = SecretManager.getSecret('ANTHROPIC_AUTH_TOKEN');
console.log(`使用 API: ${SecretManager.maskSecret(apiKey)}`);
```

