### 4. WebSocket 连接安全缺陷 🟡 **中高**

**位置**: `src/dashboard/server.ts:128`  
**问题描述**: 缺少身份认证和授权

```typescript
// 当前代码 - 无认证
fastify.get('/api/ws', { websocket: true }, (connection, req) => {
  logger.info('WebSocket client connected'); // ❌ 任何人都可以连接
});
```

**修复建议**:

```typescript
// 1. 实现 JWT 认证
import jwt from 'jsonwebtoken';

const JWT_SECRET = process.env.JWT_SECRET || 'change-me-in-production';

async function authenticateWS(connection: any, req: any) {
  const token = req.headers.authorization?.replace('Bearer ', '');

  if (!token) {
    connection.socket.close(1008, 'Missing authentication token');
    return false;
  }

  try {
    const decoded = jwt.verify(token, JWT_SECRET);
    connection.user = decoded;
    return true;
  } catch (error) {
    connection.socket.close(1008, 'Invalid token');
    return false;
  }
}

// 2. 实现速率限制
const rateLimiter = new Map<string, number[]>();

function checkRateLimit(clientId: string): boolean {
  const now = Date.now();
  const requests = rateLimiter.get(clientId) || [];
  const recentRequests = requests.filter(t => now - t < 60000); // 1分钟内

  if (recentRequests.length > 100) { // 每分钟最多100个请求
    return false;
  }

  recentRequests.push(now);
  rateLimiter.set(clientId, recentRequests);
  return true;
}

// 3. 实现 CORS 限制
await server.register(cors, {
  origin: (origin, cb) => {
    const allowedOrigins = process.env.ALLOWED_ORIGINS?.split(',') || ['http://localhost:5173'];
    if (!origin || allowedOrigins.includes(origin)) {
      cb(null, true);
    } else {
      cb(new Error('Not allowed'), false);
    }
  }
});
```

